using System;
using System.Diagnostics;

public class PdfGenerator
{
    public static void GeneratePdfReport(string htmlFilePath, string pdfPath, PageSize pageSize = PageSize.A4Portrait, bool landscape = false)
    {
        var options = new[] { 
            "--page-size", pageSize.ToString(),
            "--orientation", landscape ? "landscape" : "portrait"
        };

        using (var process = Process.Start(new ProcessStartInfo
        {
            FileName = "wkhtmltopdf",
            Arguments = string.Join(" ", options) + $" \"{htmlFilePath}\" \"{pdfPath}\"",
            RedirectStandardError = true,
            UseShellExecute = false,
            CreateNoWindow = true
        }))
        {
            process.WaitForExit();
        }
    }

    public enum PageSize { A4Portrait, A4Landscape, LetterPortrait, LetterLandscape }
}